import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, X, LogOut, ArrowRight, Activity, Globe } from 'lucide-react';

const Login = () => {
  const [view, setView] = useState('landing'); // 'landing', 'login', 'register', 'dashboard'
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [activeTab, setActiveTab] = useState('services');
  const [showModal, setShowModal] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      setIsLoggedIn(true);
      setView('dashboard');
    }
  }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    const mode = view === 'register' ? 'register' : 'login';
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${mode}`, formData);
      if (mode === 'login') {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userName', res.data.user.name);
        setIsLoggedIn(true);
        setView('dashboard');
      } else {
        alert("Account Created Successfully! Please Login.");
        setView('login');
      }
    } catch (err) { alert("Authentication Failed. Please try again."); }
  };

  // --- 1. LANDING PAGE (Entry Point) ---
  if (view === 'landing') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 font-sans">
        <div className="text-center mb-12 animate-in fade-in zoom-in duration-700">
           <div className="inline-block bg-blue-600 p-4 rounded-3xl mb-4 text-white shadow-xl shadow-blue-200">
              <ShieldCheck size={48} />
           </div>
           <h1 className="text-5xl font-black text-slate-900 tracking-tight mb-2">QUAD<span className="text-blue-600">SOLUTIONS</span></h1>
           <p className="text-slate-500 font-medium text-lg">The Future of Healthcare Credentialing & Onboarding</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl w-full">
          {/* New User Option */}
          <div onClick={() => setView('register')} className="bg-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-600 cursor-pointer transition-all duration-300 group">
             <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center mb-6 text-blue-600 group-hover:scale-110 transition">
                <UserPlus size={32} />
             </div>
             <h2 className="text-2xl font-black text-slate-800 mb-2">New Providers</h2>
             <p className="text-slate-500 mb-6 leading-relaxed">Join 5,000+ medical professionals. Start your onboarding and get credentialed in minutes.</p>
             <div className="flex items-center text-blue-600 font-bold group-hover:gap-2 transition-all">
                Create Account <ArrowRight size={20} className="ml-2" />
             </div>
          </div>

          {/* Existing Client Option */}
          <div onClick={() => setView('login')} className="bg-slate-900 p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-400 cursor-pointer transition-all duration-300 group text-white">
             <div className="w-16 h-16 bg-white/10 rounded-2xl flex items-center justify-center mb-6 text-blue-400 group-hover:scale-110 transition">
                <LogIn size={32} />
             </div>
             <h2 className="text-2xl font-black mb-2">Existing Clients</h2>
             <p className="text-slate-300/70 mb-6 leading-relaxed">Access your secure dashboard, track pending requests, and manage active licenses.</p>
             <div className="flex items-center text-blue-400 font-bold group-hover:gap-2 transition-all">
                Sign In <ArrowRight size={20} className="ml-2" />
             </div>
          </div>
        </div>
        
        <p className="mt-12 text-slate-400 text-sm font-bold tracking-widest uppercase">Trusted by leading hospitals worldwide</p>
      </div>
    );
  }

  // --- 2. AUTH FORMS (Login/Register) ---
  if (view === 'login' || view === 'register') {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-white p-10 rounded-[3rem] shadow-2xl relative">
          <button onClick={() => setView('landing')} className="absolute top-8 right-8 text-slate-300 hover:text-slate-600 font-bold transition">Back</button>
          <h2 className="text-4xl font-black mb-2 text-slate-900">{view === 'login' ? 'Welcome Back' : 'Get Started'}</h2>
          <p className="text-slate-400 mb-8 font-medium">{view === 'login' ? 'Access your secure portal' : 'Create your provider profile'}</p>
          
          <form onSubmit={handleAuth} className="space-y-4">
            {view === 'register' && (
              <input type="text" placeholder="Full Name" className="w-full p-4 bg-slate-50 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none" onChange={(e) => setFormData({...formData, name: e.target.value})} required />
            )}
            <input type="email" placeholder="Email Address" className="w-full p-4 bg-slate-50 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none" onChange={(e) => setFormData({...formData, email: e.target.value})} required />
            <input type="password" placeholder="Password" className="w-full p-4 bg-slate-50 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none" onChange={(e) => setFormData({...formData, password: e.target.value})} required />
            <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-lg shadow-lg hover:bg-blue-700 transition">
              {view === 'login' ? 'Sign In' : 'Create My Account'}
            </button>
          </form>
          <p onClick={() => setView(view === 'login' ? 'register' : 'login')} className="mt-6 text-center text-slate-400 font-bold text-sm cursor-pointer hover:text-blue-600 transition">
            {view === 'login' ? "Don't have an account? Register" : "Already have an account? Login"}
          </p>
        </div>
      </div>
    );
  }

  // --- 3. LOGGED IN DASHBOARD (User Services & Tracking) ---
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <nav className="bg-white shadow-sm p-4 sticky top-0 z-50 border-b">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <h1 className="text-xl font-black text-blue-600 tracking-tight italic">QUAD SOLUTIONS</h1>
          <div className="flex gap-6 items-center">
             <button onClick={() => setActiveTab('services')} className={`text-sm font-bold ${activeTab === 'services' ? 'text-blue-600' : 'text-slate-400'}`}>Services</button>
             <button onClick={() => setActiveTab('tracking')} className={`text-sm font-bold ${activeTab === 'tracking' ? 'text-blue-600' : 'text-slate-400'}`}>My Tracking</button>
             <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 font-bold text-sm"><LogOut size={18}/></button>
          </div>
        </div>
      </nav>

      <main className="p-6 md:p-10 max-w-7xl mx-auto w-full">
        {activeTab === 'services' ? (
          <section className="animate-in fade-in duration-500">
             <h2 className="text-3xl font-black text-slate-900 mb-8">Available Onboarding Services</h2>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {['Medical License Renewal', 'Insurance Enrollment', 'DEA Certification'].map((item, idx) => (
                  <div key={idx} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 hover:shadow-xl transition duration-300">
                    <div className="w-12 h-12 bg-blue-50 rounded-xl flex items-center justify-center mb-4 text-blue-600"><FileText/></div>
                    <h3 className="text-xl font-bold mb-2">{item}</h3>
                    <p className="text-slate-400 text-sm mb-6 leading-relaxed">Full support for healthcare providers and clinical facilities.</p>
                    <button onClick={() => setShowModal(true)} className="w-full bg-slate-100 py-3 rounded-xl font-bold text-slate-800 hover:bg-blue-600 hover:text-white transition">Apply Now</button>
                  </div>
                ))}
             </div>
          </section>
        ) : (
          <section className="animate-in fade-in duration-500">
             <h2 className="text-2xl font-black mb-6">Status Tracking</h2>
             <div className="bg-white rounded-3xl p-10 shadow-sm border border-slate-100 text-center">
                <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300"><Activity size={40}/></div>
                <p className="text-slate-400 font-medium">You haven't submitted any credentialing requests yet.</p>
             </div>
          </section>
        )}
      </main>

      {/* --- APPLICATION MODAL --- */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 z-[100]">
          <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl p-10 animate-in zoom-in duration-200">
            <h2 className="text-2xl font-bold mb-4">Start Onboarding</h2>
            <form onSubmit={(e) => { e.preventDefault(); alert("Request Submitted!"); setShowModal(false); }} className="space-y-4">
              <input type="text" placeholder="State License ID" className="w-full p-4 bg-slate-50 rounded-2xl border-none" required />
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black">Submit Request</button>
              <button onClick={() => setShowModal(false)} type="button" className="w-full text-slate-400 font-bold">Cancel</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Login;
